const emojis = {
  success: [
    ["✅", 3],
    ["🎉", 2, true],
    ["🤝", 1],
    ["💚", 2],
    ["👍", 3, true],
  ] as EmojiEntry[],
  warning: [
    ["⚠️", 3],
    ["😬", 2],
    ["👀", 2],
    ["🫣", 1],
  ] as EmojiEntry[],
  nudge: [
    ["🫨", 2, true],
    ["🙉", 3],
    ["👉", 2, true],
    ["😳", 1],
  ] as EmojiEntry[],
  error: [
    ["⛔️", 3],
    ["🚨", 1],
    ["🚫", 3],
    ["🙅‍♀️", 1, true],
  ] as EmojiEntry[],
  buzz: [
    ["🐝", 12, true],
    ["🍯", 8],
    ["🌼", 3],
  ] as EmojiEntry[],
};

function expandWeighted(entries: EmojiEntry[]): EmojiOption[] {
  return entries.flatMap(([emoji, weight, canFlip]) =>
    Array.from({ length: weight }, () => ({
      emoji,
      canFlip: canFlip ?? false,
    })),
  );
}

